#!/bin/bash
IFS='.' read -ra ip <<< "$1"; num=$(( ip[0]*256**3 + ip[1]*256**2 + ip[2]*256 + ip[3] )); cidr=$2; host=$((32-cidr)); size=$((2**host)); net=$((num/size*size)); bcast=$((net+size-1)); first=$((net+1)); last=$((bcast-1)); for num in "$first" "$last"; do for s in 24 16 8 0; do printf "%d" "$((num>>s&255))"; if (( s != 0 )); then printf "."; fi; done; if (( num == first )); then printf " - "; else echo; fi; done
